// Parse payload if it's a string
let rawData = msg.payload;
if (typeof rawData === 'string') {
    try {
        rawData = JSON.parse(rawData);
    } catch(e) {
        node.error("Failed to parse JSON: " + e.message);
        return null; // Stop flow
    }
}

if (!rawData || typeof rawData !== 'object') {
    node.error("Invalid payload type");
    return null;
}

// Metadata
msg.measurement = "telemetry";
msg.tags = {
    node: "01", // Default node ID
    version: rawData.version || "0.1.0"
};

// Extract node ID from MQTT topic if possible to be dynamic
if (msg.topic) {
    const parts = msg.topic.split('/');
    if (parts.length >= 2) {
        msg.tags.node = parts[1]; // e.g. "01" from "honguera/01/telemetry"
    }
}

let fields = {};

// Defensive mapping function
function addField(sourceObj, sourceKey, targetKey, isInt, isBool) {
    if (sourceObj === undefined || sourceObj === null) return;
    const val = sourceObj[sourceKey];
    if (val === undefined || val === null) return;

    if (typeof val === 'number') {
        if (isNaN(val)) return;
        fields[targetKey] = isInt ? Math.round(val) : val;
    } else if (typeof val === 'boolean') {
        if (isBool) {
            fields[targetKey] = val ? 1 : 0;
        } else {
            fields[targetKey] = val;
        }
    } else if (typeof val === 'string') {
        // Try to parse number if it looks like one
        const num = parseFloat(val);
        if (!isNaN(num)) {
            fields[targetKey] = isInt ? Math.round(num) : num;
        }
    }
}

// Map sensors
if (rawData.sensors) {
    addField(rawData.sensors, 'temperature', 'air_temperature', false, false);
    addField(rawData.sensors, 'humidity', 'air_humidity', false, false);
    addField(rawData.sensors, 'co2', 'co2_ppm', true, false);
    addField(rawData.sensors, 'water_temp', 'water_temp', false, false);
    addField(rawData.sensors, 'sustrate_moisture', 'substrate_moisture_pct', true, false);
    addField(rawData.sensors, 'enzymatic_orp', 'substrate_orp_mv', false, false);
}

// Map actuators
if (rawData.actuators) {
    addField(rawData.actuators, 'heater', 'heater', true, true);
    addField(rawData.actuators, 'humidifier', 'humidifier', true, true);
    addField(rawData.actuators, 'extractor_aire', 'extractor_aire', true, true);
    // Also check backward compatible name 'extractor'
    if (rawData.actuators.extractor_aire === undefined) {
        addField(rawData.actuators, 'extractor', 'extractor_aire', true, true);
    }
    addField(rawData.actuators, 'valvula_riego', 'valvula_riego', true, true);
    addField(rawData.actuators, 'light', 'light', true, true);
}

// Map RSSI
addField(rawData, 'rssi', 'rssi', true, false);

// Map safety block
if (rawData.safety) {
    addField(rawData.safety, 'dry_run_actuators', 'dry_run_actuators', true, true);
    addField(rawData.safety, 'actuator_active_high', 'actuator_active_high', true, true);
    addField(rawData.safety, 'orp_anoxia_alert', 'orp_anoxia_alert', true, true);
    addField(rawData.safety, 'anoxia_reading_count', 'anoxia_reading_count', true, false);
    addField(rawData.safety, 'recovery_reading_count', 'recovery_reading_count', true, false);
}

// Verify we have at least one valid field to write
if (Object.keys(fields).length === 0) {
    node.warn("No valid fields found to write to InfluxDB");
    return null;
}

msg.payload = fields;
return msg;
